import React, { useCallback } from 'react';
import { Button, Modal, dispatchAppToast, DocumentHistoryModal } from '@linm-soft/common-components';
import { UnsavedChangesModal } from '../../../../../components/form';
import {
  VoucherSearchSlideout,
  ProcessingLevelApproveModal,
  VoucherPrintModal,
  VoucherPostedLedgerModal,
} from '../../../../../components/voucher';
import { useAppDispatch } from '../../../../../store/hooks';
import { InvoiceAllocateModal } from '../../../../../components/kt/InvoiceAllocateModal';
import type { CashVoucherFormViewModel } from '../hooks/useCashVoucherFormController';
import { formatProcessingLevelFromOptions } from '../../../../../utils/voucherProcessingLevelOptions';
import styles from '../../../../../styles/documentForm.module.css';

export const CashVoucherFormModals: React.FC<{ vm: CashVoucherFormViewModel }> = ({ vm }) => {
  const dispatch = useAppDispatch();
  const onHistoryError = useCallback((message: string) => {
    dispatchAppToast(dispatch, { message, type: 'error' });
  }, [dispatch]);

  const {
    cfg,
    labels,
    isNew,
    id,
    voucherNumber,
    processingLevel,
    processingOpts,
    showSearchSlideout,
    setShowSearchSlideout,
    handleOpenFromSearch,
    showApproveModal,
    setShowApproveModal,
    handleApproveConfirm,
    approving,
    showPrintModal,
    setShowPrintModal,
    showHistoryModal,
    setShowHistoryModal,
    handlePrintConfirm,
    printing,
    showAllocateModal,
    setShowAllocateModal,
    customerId,
    totalAmount,
    handleAllocateConfirm,
    showUnsavedModal,
    cancelLeave,
    confirmLeave,
    tid,
    showDeleteModal,
    setShowDeleteModal,
    handleDelete,
    deleting,
    showLedgerModal,
    setShowLedgerModal,
  } = vm;

  return (
    <>
      <VoucherSearchSlideout
        isOpen={showSearchSlideout}
        onClose={() => setShowSearchSlideout(false)}
        title={`Tìm ${labels.title.toLowerCase()}`}
        testIdPrefix={cfg.testIdPrefix}
        listScope={cfg.searchListScope}
        fetchList={cfg.fetch}
        onOpenVoucher={handleOpenFromSearch}
        processingLevelFilterOptions={processingOpts}
        formatProcessingLevel={level => formatProcessingLevelFromOptions(level, processingOpts)}
      />

      <ProcessingLevelApproveModal
        isOpen={showApproveModal}
        onClose={() => setShowApproveModal(false)}
        currentLevel={processingLevel}
        levelOptions={processingOpts}
        onConfirm={handleApproveConfirm}
        saving={approving}
        testIdPrefix={cfg.testIdPrefix}
      />

      <VoucherPrintModal
        isOpen={showPrintModal}
        onClose={() => setShowPrintModal(false)}
        voucherTitle={!isNew ? `${labels.title} — ${voucherNumber || '...'}` : undefined}
        onPrint={handlePrintConfirm}
        printing={printing}
        testIdPrefix={cfg.testIdPrefix}
      />

      {'documentHistoryType' in cfg && cfg.documentHistoryType && 'documentHistoryClient' in cfg && cfg.documentHistoryClient && id && (
        <DocumentHistoryModal
          isOpen={showHistoryModal}
          onClose={() => setShowHistoryModal(false)}
          client={cfg.documentHistoryClient}
          documentType={cfg.documentHistoryType}
          documentId={id}
          documentCode={voucherNumber || undefined}
          testIdPrefix={cfg.testIdPrefix}
          onError={onHistoryError}
        />
      )}

      <InvoiceAllocateModal
        isOpen={showAllocateModal}
        onClose={() => setShowAllocateModal(false)}
        customerId={customerId}
        voucherTotal={totalAmount}
        onConfirm={handleAllocateConfirm}
        testIdPrefix={cfg.testIdPrefix}
      />

      <UnsavedChangesModal
        isOpen={showUnsavedModal}
        onStay={cancelLeave}
        onLeave={confirmLeave}
        data-testid={tid('unsaved-modal')}
      />

      <Modal isOpen={showDeleteModal} onClose={() => setShowDeleteModal(false)} title={`Xác nhận xóa ${labels.title.toLowerCase()}`}>
        <p>Bạn có chắc muốn xóa chứng từ này? Hành động không thể hoàn tác.</p>
        <div className={styles.modalActions}>
          <Button variant="secondary" onClick={() => setShowDeleteModal(false)}>Hủy</Button>
          <Button variant="danger" onClick={handleDelete} loading={deleting}>Xóa</Button>
        </div>
      </Modal>

      {!isNew && id && (
        <VoucherPostedLedgerModal
          isOpen={showLedgerModal}
          onClose={() => setShowLedgerModal(false)}
          voucherTitle={`${labels.title} — ${voucherNumber || '...'}`}
          testIdPrefix={cfg.testIdPrefix}
          fetchPostedLedger={() => cfg.getPostedLedger(id)}
          fetchPostingStatus={() => cfg.getPostingStatus(id)}
        />
      )}
    </>
  );
};
